"use strict";parserFactory.register("creativenovels.com",()=>new CreativeNovelsParser);class CreativeNovelsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div#chapter_list_novel_page, div.post_box a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.entry-content.content")}removeUnwantedElementsFromContentElement(e){util.removeElements(e.querySelectorAll("div.team, div.x-donate-1, div.navigation, div.navi, header.entry-header")),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("header.entry-header h1")}findCoverImageUrl(e){let r=e.querySelector("img.book_cover");return null===r?util.getFirstImgSrc(e,"header"):r.src}makeHiddenNodesVisible(e){e.removeAttribute("style")}}